public OngoingInjecter filterCandidate(final Collection<Object> mocks, final Field field, final Object fieldInstance) {
        // First filter by type
        List<Object> mockTypeMatches = new ArrayList<Object>();
        for (Object mock : mocks) {
            if (field.getType().isAssignableFrom(mock.getClass())) {
                mockTypeMatches.add(mock);
            }
        }
        Collection<Object> candidates = mockTypeMatches.isEmpty() ? new ArrayList<Object>(mocks) : mockTypeMatches;

        // Then, if multiple, filter by name
        if (candidates.size() > 1) {
            List<Object> mockNameMatches = new ArrayList<Object>();
            for (Object mock : candidates) {
                if (field.getName().equals(mockUtil.getMockName(mock).toString())) {
                    mockNameMatches.add(mock);
                }
            }
            if (!mockNameMatches.isEmpty()) {
                candidates = mockNameMatches;
            }
        }

        if (candidates.size() == 1) {
            final Object matchingMock = candidates.iterator().next();

            return new OngoingInjecter() {
                public Object thenInject() {
                    try {
                        if (!new BeanPropertySetter(fieldInstance, field).set(matchingMock)) {
                            new FieldSetter(fieldInstance, field).set(matchingMock);
                        }
                    } catch (RuntimeException e) {
                        new Reporter().cannotInjectDependency(field, matchingMock, e);
                    }
                    return matchingMock;
                }
            };
        }

        return new OngoingInjecter() {
            public Object thenInject() {
                return null;
            }
        };

    }

OngoingInjecter filterCandidateAlias(
            Collection<Object> mocks,
            Field fieldToBeInjected,
            Object fieldInstance
    ) {
        return filterCandidate(mocks, fieldToBeInjected, fieldInstance);
    }

public OngoingInjecter filterCandidateByName(Collection<Object> mocks,
            Field field, Object fieldInstance) {
        List<Object> mockNameMatches = new ArrayList<Object>();
        if (mocks.size() > 1) {
            for (Object mock : mocks) {
                if (field.getName().equals(mockUtil.getMockName(mock).toString())) {
                    mockNameMatches.add(mock);
                }
            }
            return filterCandidate(mockNameMatches, field,
                    fieldInstance);
        }
        return filterCandidate(mocks, field, fieldInstance);
    }

public OngoingInjecter filterCandidateByType(Collection<Object> mocks, Field field, Object fieldInstance) {
        List<Object> mockTypeMatches = new ArrayList<Object>();
        for (Object mock : mocks) {
            if (field.getType().isAssignableFrom(mock.getClass())) {
                mockTypeMatches.add(mock);
            }
        }

        return filterCandidate(mockTypeMatches, field, fieldInstance);
    }

private boolean injectMockCandidatesOnFields(Set<Object> mocks, Object instance, boolean injectionOccurred, List<Field> orderedInstanceFields) {
        for (Iterator<Field> it = orderedInstanceFields.iterator(); it.hasNext(); ) {
            Field field = it.next();
            Object injected = mockCandidateFilter.filterCandidate(mocks, field, instance).thenInject();
            if (injected != null) {
                injectionOccurred |= true;
                mocks.remove(injected);
                it.remove();
            }
        }
        return injectionOccurred;
    }
